(window.webpackJsonp=window.webpackJsonp||[]).push([[1088],{1020:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">nums</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">lower</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">upper</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> countRangeSum = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">nums, lower, upper</span>) </span>{\\n  \\n  <span class=\\"hljs-keyword\\">let</span> n = nums.length;\\n  <span class=\\"hljs-keyword\\">let</span> sums = <span class=\\"hljs-built_in\\">Array</span>(n+<span class=\\"hljs-number\\">1</span>).fill(<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">for</span> (<span class=\\"hljs-keyword\\">let</span> i = <span class=\\"hljs-number\\">0</span>; i &lt; n; ++i){\\n     sums[i + <span class=\\"hljs-number\\">1</span>] = sums[i] + nums[i]\\n  }\\n     \\n  <span class=\\"hljs-keyword\\">return</span> divid(<span class=\\"hljs-number\\">0</span>, n)\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">divid</span>(<span class=\\"hljs-params\\">start,end</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(end-start&lt;=<span class=\\"hljs-number\\">0</span>)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> mid=<span class=\\"hljs-built_in\\">Math</span>.floor((start+end)/<span class=\\"hljs-number\\">2</span>)\\n    <span class=\\"hljs-keyword\\">let</span> count=divid(start,mid)+divid(mid+<span class=\\"hljs-number\\">1</span>,end)\\n    <span class=\\"hljs-keyword\\">let</span> rangeStart=mid+<span class=\\"hljs-number\\">1</span>,rangeEnd=mid+<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=start;i&lt;=mid;i++){\\n      <span class=\\"hljs-comment\\">// \u6bcf\u4e00\u6b21\u904d\u5386\u90fd\u627e\u5230\u80fd\u6ee1\u8db3</span>\\n      <span class=\\"hljs-comment\\">// 1. rangeStart\u662f\u6ee1\u8db3SUM(i,rangeStart)&gt;=lower\u7684\u4e00\u4e2a\u4f4d\u7f6e</span>\\n      <span class=\\"hljs-comment\\">// 2. rangeEnd\u662f\u6ee1\u8db3SUM(i,rangeEnd)&gt;upper\u7684\u7b2c\u4e00\u4e2a\u4f4d\u7f6e</span>\\n      <span class=\\"hljs-comment\\">// \u5b83\u4eec\u76f8\u51cf\u5c31\u662f\u5f53\u524di\u4e3a\u8d77\u70b9\u5b58\u5728\u7684\u533a\u95f4\u4e2a\u6570</span>\\n      <span class=\\"hljs-keyword\\">while</span>(rangeStart&lt;=end &amp;&amp; sums[rangeStart]-sums[i]&lt;lower)\\n        rangeStart++\\n      <span class=\\"hljs-keyword\\">while</span>(rangeEnd&lt;=end &amp;&amp; sums[rangeEnd]-sums[i]&lt;=upper)\\n        rangeEnd++\\n      count+=rangeEnd-rangeStart\\n    }\\n    merge(start,mid,end)\\n    <span class=\\"hljs-comment\\">// console.log(sums)</span>\\n    <span class=\\"hljs-keyword\\">return</span> count\\n  }\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">merge</span>(<span class=\\"hljs-params\\">start,mid,end</span>)</span>{\\n    <span class=\\"hljs-keyword\\">let</span> res=[]\\n    <span class=\\"hljs-keyword\\">let</span> i=start,j=mid+<span class=\\"hljs-number\\">1</span>\\n    <span class=\\"hljs-keyword\\">while</span>(i&lt;mid+<span class=\\"hljs-number\\">1</span> || j&lt;end+<span class=\\"hljs-number\\">1</span>){\\n      <span class=\\"hljs-keyword\\">if</span>(i===mid+<span class=\\"hljs-number\\">1</span>){\\n        res.push(sums[j++])\\n      }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(j===end+<span class=\\"hljs-number\\">1</span>){\\n        res.push(sums[i++])\\n      }<span class=\\"hljs-keyword\\">else</span> <span class=\\"hljs-keyword\\">if</span>(sums[i]&lt;sums[j]){\\n        res.push(sums[i++])\\n      }<span class=\\"hljs-keyword\\">else</span>{\\n        res.push(sums[j++])\\n      }\\n    }\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=start;i&lt;=end;i++){\\n      sums[i]=res[i-start]\\n    }\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"count-of-range-sum","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u8fd9\u9053\u9898\u867d\u7136\u4e0d\u80fd\u76f4\u63a5\u6392\u5e8f\u5904\u7406\uff0c\u4f46\u662f\u5148\u6c42\u51fa\u524d\u7f00\u548c\u6570\u7ec4<code>sums</code>\uff0c\u5bf9\u4e8e<code>sums</code>\u5185\u90e8\uff0c\u53ea\u8981\u6ee1\u8db3<code>j&gt;i</code>\uff0c\\n\u4ed6\u4eec\u7684\u533a\u95f4\u548c\u5c31\u662f<code>sums[j]-sums[i]</code>\uff0c\u5177\u4f53\u6392\u5e8f\u5982\u4f55\u53ef\u4ee5\u4e0d\u7528\u8003\u8651\uff0c\u56e0\u6b64\u901a\u8fc7\u5f52\u5e76\u6392\u5e8f\u4e0d\u65ad\u6784\u5efa<code>\u5de6[start,mid]</code>\u548c<code>\u53f3[mid+1,end]</code>\u7684<strong>\u6709\u5e8f\u6570\u7ec4</strong>\uff1b</p>\\n<p>\u5bf9\u8fd9\u4e24\u4e2a\u6709\u5e8f\u6570\u7ec4\uff0c\u8bbe\u5b9a2\u4e2a\u6307\u9488<code>rangeStart</code>\uff0c<code>rangeEnd</code>\uff0c\u5176\u4e2d<code>rangeStart</code>\u7684\u8303\u56f4\u5728<code>[start,mid]</code>\uff0c\u4e5f\u5c31\u662f\u5de6\u534a\u6bb5\uff1b</p>\\n<p><code>rangeEnd</code>\u7684\u8303\u56f4\u5728<code>[mid+1,end]</code>\uff0c\u4e5f\u5c31\u662f\u53f3\u534a\u6bb5\uff1b</p>\\n<p>\u56e0\u4e3a\u53f3\u534a\u6bb5\u7684\u6240\u6709\u7d22\u5f15\u90fd\u80fd\u5927\u4e8e\u5de6\u534a\u6bb5\u7684\u6240\u6709\u7d22\u5f15\uff0c\u4e5f\u5c31\u662f\u8bf4\u6ee1\u8db3<code>rangeEnd&gt;rangeStart</code>\uff0c\u56e0\u6b64\u53ef\u4ee5\u5bf9\u5b83\u4eec\u6392\u5e8f\uff0c\u5e76\u4e14\u8ba1\u7b97\u5b83\u4eec\u7684\u533a\u95f4\u548c<code>sums[rangeEnd]-sums[rangeStart]</code>\u3002</p>\\n<p>\u4e4b\u6240\u4ee5\u5bf9\u5de6\u534a\u6bb5\u548c\u53f3\u534a\u6bb5\u6392\u5e8f\uff0c\u56e0\u4e3a\u6392\u5e8f\u540e\uff0c\u6211\u4eec\u53ef\u4ee5\u5728\u904d\u5386\u5de6\u534a\u6bb5\u7684\u65f6\u5019\uff0c\u5f88\u65b9\u4fbf\u5730\u627e\u51fa\uff1a</p>\\n<ol>\\n<li>\\n<p><code>rangeStart</code>\u4e3a\u6ee1\u8db3<code>\u533a\u95f4(i,rangeStart)&gt;=lower</code>\u7684\u4e00\u4e2a\u4f4d\u7f6e</p>\\n</li>\\n<li>\\n<p><code>rangeEnd</code>\u662f\u6ee1\u8db3<code>\u533a\u95f4(i,rangeEnd)&gt;upper</code>\u7684\u7b2c\u4e00\u4e2a\u4f4d\u7f6e</p>\\n</li>\\n<li>\\n<p>\u5c06\u5b83\u4eec\u7684\u4f4d\u7f6e\u4e4b\u5dee\uff0c\u4e5f\u5c31\u662f\u5728\u5185\u90e8\u7684\u6570\u5b57\u90fd\u80fd\u6ee1\u8db3\u8981\u6c42\u7684\u6570\u91cf\uff0c\u6dfb\u52a0\u5230<code>count</code>\u4e0a\u3002</p>\\n</li>\\n</ol>\\n<p>\u5904\u7406\u597d\u5f53\u524d\u6ee1\u8db3\u8981\u6c42\u533a\u95f4\u6570\u91cf\u540e\uff0c\u9700\u8981\u5bf9\u5f53\u524d\u7684\u5de6\u534a\u6bb5\u548c\u53f3\u534a\u6bb5\u5408\u5e76\u6392\u5e8f\uff0c\u8fd9\u5c31\u662f\u57fa\u7840\u5f52\u5e76\u6392\u5e8f\u7684<code>merge</code>\u65b9\u6cd5\u3002</p>\\n","content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u6574\u6570\u6570\u7ec4\xa0<code>nums</code> \u4ee5\u53ca\u4e24\u4e2a\u6574\u6570\xa0<code>lower</code> \u548c <code>upper</code> \u3002\u6c42\u6570\u7ec4\u4e2d\uff0c\u503c\u4f4d\u4e8e\u8303\u56f4 <code>[lower, upper]</code> \uff08\u5305\u542b\xa0<code>lower</code>\xa0\u548c\xa0<code>upper</code>\uff09\u4e4b\u5185\u7684 <strong>\u533a\u95f4\u548c\u7684\u4e2a\u6570</strong> \u3002</p>\\n\\n<p><strong>\u533a\u95f4\u548c</strong>\xa0<code>S(i, j)</code>\xa0\u8868\u793a\u5728\xa0<code>nums</code>\xa0\u4e2d\uff0c\u4f4d\u7f6e\u4ece\xa0<code>i</code>\xa0\u5230\xa0<code>j</code>\xa0\u7684\u5143\u7d20\u4e4b\u548c\uff0c\u5305\u542b\xa0<code>i</code>\xa0\u548c\xa0<code>j</code>\xa0(<code>i</code> \u2264 <code>j</code>)\u3002</p>\\n\\n<p>\xa0</p>\\n<strong>\u793a\u4f8b 1\uff1a</strong>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [-2,5,-1], lower = -2, upper = 2\\n<strong>\u8f93\u51fa\uff1a</strong>3\\n<strong>\u89e3\u91ca\uff1a</strong>\u5b58\u5728\u4e09\u4e2a\u533a\u95f4\uff1a[0,0]\u3001[2,2] \u548c [0,2] \uff0c\u5bf9\u5e94\u7684\u533a\u95f4\u548c\u5206\u522b\u662f\uff1a-2 \u3001-1 \u30012 \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>nums = [0], lower = 0, upper = 0\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 <= nums.length <= 10<sup>5</sup></code></li>\\n\\t<li><code>-2<sup>31</sup> <= nums[i] <= 2<sup>31</sup> - 1</code></li>\\n\\t<li><code>-10<sup>5</sup> <= lower <= upper <= 10<sup>5</sup></code></li>\\n\\t<li>\u9898\u76ee\u6570\u636e\u4fdd\u8bc1\u7b54\u6848\u662f\u4e00\u4e2a <strong>32 \u4f4d</strong> \u7684\u6574\u6570</li>\\n</ul>\\n","title":"327. \u533a\u95f4\u548c\u7684\u4e2a\u6570","relatedTags":["\u6392\u5e8f","\u6811\u72b6\u6570\u7ec4","\u7ebf\u6bb5\u6811","\u4e8c\u5206\u67e5\u627e","\u5206\u6cbb\u7b97\u6cd5"],"difficult":"Hard","lang":["javascript"],"uniqueID":"327"}')}}]);